	errs := make(map[string]error)
	for _, sw := range a.GetAllSealInfoByPriority() {
		for _, blobInfo := range ciphertext.Slots {
			pt, oldKey, err := a.tryDecrypt(ctx, sw, blobInfo, options)
			if oldKey {
				a.logger.Trace("decrypted using OldKey", "seal", sw.Name)
				return pt, false, err
			}
			if err == nil {
				a.logger.Trace("decrypted value using seal", "seal", sw.Name)
				return pt, isUpToDate, nil
			}
			errs[sw.Name] = err
		}
	}

	return nil, false, JoinSealWrapErrors("error decrypting seal wrapped value", errs)
}

