	// Encrypt uses the underlying seal to encrypt the plaintext and returns it.
func (a *access) Encrypt(ctx context.Context, plaintext []byte, options ...wrapping.Option) (*MultiWrapValue, map[string]error) {
	var slots []*wrapping.BlobInfo
	errs := make(map[string]error)

	for _, sw := range a.GetEnabledSealInfoByPriority() {
		var encryptErr error
		defer func(now time.Time) {
			metrics.MeasureSince([]string{"seal", "encrypt", "time"}, now)
			metrics.MeasureSince([]string{"seal", sw.Name, "encrypt", "time"}, now)

			if encryptErr != nil {
				metrics.IncrCounter([]string{"seal", "encrypt", "error"}, 1)
				metrics.IncrCounter([]string{"seal", sw.Name, "encrypt", "error"}, 1)
			}
		}(time.Now())

		metrics.IncrCounter([]string{"seal", "encrypt"}, 1)
		metrics.IncrCounter([]string{"seal", sw.Name, "encrypt"}, 1)

		ciphertext, encryptErr := sw.Wrapper.Encrypt(ctx, plaintext, options...)
		if encryptErr != nil {
			a.logger.Warn("error encrypting with seal", "seal", sw.Name)
			a.logger.Trace("error encrypting with seal", "seal", sw.Name, "err", encryptErr)

			errs[sw.Name] = encryptErr
			sw.Healthy = false
		} else {
			a.logger.Trace("encrypted value using seal", "seal", sw.Name, "keyId", ciphertext.KeyInfo.KeyId)

			slots = append(slots, ciphertext)
		}
	}

	if len(slots) == 0 {
		a.logger.Error("all seals failed to encrypt value")
		return nil, errs
	}

	a.logger.Trace("successfully encrypted value", "encryption seal wrappers", len(slots), "total enabled seal wrappers",
		len(a.GetEnabledSealInfoByPriority()))
	ret := &MultiWrapValue{
		Generation: a.Generation(),
		Slots:      slots,
	}

	// cache key IDs
	a.keyIdSet.set(ret)

	return ret, errs
}

